document.addEventListener("DOMContentLoaded", function () { const body = document.body; const searchToggle = document.querySelector(".search-toggle"); const searchPanel = document.querySelector(".search-panel"); const searchDialog = searchPanel ? searchPanel.querySelector(".search-panel__dialog") : null; const searchClose = searchPanel ? searchPanel.querySelector(".search-panel__close") : null; const searchInput = searchPanel ? searchPanel.querySelector(".search-field") : null; const navToggle = document.querySelector(".nav-toggle"); const megaPanel = document.querySelector(".mega-panel"); if (!searchToggle || !searchPanel) { return; } function closeSearch() { searchToggle.setAttribute("aria-expanded", "false"); body.classList.remove("search-open"); searchPanel.setAttribute("aria-hidden", "true"); } searchToggle.addEventListener("click", function () { const expanded = searchToggle.getAttribute("aria-expanded") === "true"; searchToggle.setAttribute("aria-expanded", String(!expanded)); body.classList.toggle("search-open", !expanded); searchPanel.setAttribute("aria-hidden", String(expanded)); if (!expanded && searchInput) { window.setTimeout(function () { searchInput.focus(); }, 40); } if (!expanded && navToggle) { navToggle.setAttribute("aria-expanded", "false"); body.classList.remove("nav-open"); if (megaPanel) { megaPanel.setAttribute("aria-hidden", "true"); } } }); document.addEventListener("click", function (event) { const target = event.target; if ( body.classList.contains("search-open") && searchDialog && !searchDialog.contains(target) && !searchToggle.contains(target) ) { closeSearch(); } }); document.addEventListener("keydown", function (event) { if (event.key === "Escape" && body.classList.contains("search-open")) { closeSearch(); } }); if (searchClose) { searchClose.addEventListener("click", function () { closeSearch(); }); } window.addEventListener("resize", function () { if (window.innerWidth <= 560 && body.classList.contains("search-open")) { searchPanel.setAttribute("aria-hidden", "false"); } }); });
